    }

    /**
     * @param  array<int, array<string, mixed>>  $rows
     */
    private function seedTable(string $table, array $rows): void
    {
        if ($rows === []) {
            return;
        }

        $columns = array_flip(Schema::getColumnListing($table));
        $rows = array_map(
            static fn (array $row): array => array_intersect_key($row, $columns),
            $rows,
        );

        foreach (array_chunk($rows, 100) as $chunk) {
            $updateColumns = array_values(array_diff(array_keys($chunk[0]), ['id']));
            DB::table($table)->upsert($chunk, ['id'], $updateColumns);
        }
    }

    /**
     * @param  array<int, array<string, mixed>>  $groups
     * @return array<int, array<string, mixed>>
     */
    private function withoutDeferredGroupKeys(array $groups): array
    {
        return array_map(static function (array $group): array {
            $group['parent_group_id'] = null;
            $group['source_group_id'] = null;
            $group['initiated_by_person_id'] = null;

            return $group;
        }, $groups);
    }
}
